"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[89251],{2113(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>h,frontMatter:()=>s,metadata:()=>n,toc:()=>d});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 and IAS 38/training-costs-to-fulfil-a-contract--9acf8915cc","title":"Training Costs to Fulfil a Contract (IFRS 15)","description":"March 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 and IAS 38/Training Costs to Fulfil a Contract (IFRS 15).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 and IAS 38","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"training-costs-to-fulfil-a-contract--9acf8915cc","title":"Training Costs to Fulfil a Contract (IFRS 15)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Principal versus Agent\uFF1ASoftware Reseller (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/principal-versus-agent-software-rese-25f569f589"},"next":{"title":"Definition of a Lease\u2014Decision-making Rights (IFRS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-decision-makin-aa1a02b69f"}}');var a=i(74848),o=i(28453);let s={id:"training-costs-to-fulfil-a-contract--9acf8915cc",title:"Training Costs to Fulfil a Contract (IFRS 15)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc",sidebar_position:1},r="Training Costs to Fulfil a Contract (IFRS 15)",c={},d=[{value:"Which IFRS Standard applies to the training costs?",id:"which-ifrs-standard-applies-to-the-training-costs",level:2},{value:"Application of IAS 38",id:"application-of-ias-38",level:2}];function f(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"training-costs-to-fulfil-a-contract-ifrs-15",children:"Training Costs to Fulfil a Contract (IFRS 15)"})}),"\n",(0,a.jsx)(t.p,{children:"March 2020"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about training costs incurred to fulfil a contract with a customer. In the fact pattern described in the request:"}),"\n",(0,a.jsx)(t.p,{children:"a. an entity enters into a contract with a customer that is within the scope of IFRS 15. The contract is for the supply of outsourced services.\nb. to be able to provide the services to the customer, the entity incurs costs to train its employees so that they understand the customer\u2019s equipment and processes. The training costs are as described in paragraph 15 of IAS 38 Intangible Assets\u2014the entity has insufficient control over the expected future economic benefits arising from the training to meet the definition of an intangible asset because employees can leave the entity\u2019s employment. Applying IFRS 15, the entity does not identify the training activities as a performance obligation.\nc. the contract permits the entity to charge to the customer the costs of training (i) the entity\u2019s employees at the beginning of the contract, and (ii) new employees that the entity hires as a result of any expansion of the customer\u2019s operations."}),"\n",(0,a.jsx)(t.p,{children:"The request asked whether the entity recognises the training costs as an asset or an expense when incurred."}),"\n",(0,a.jsx)(t.h2,{id:"which-ifrs-standard-applies-to-the-training-costs",children:"Which IFRS Standard applies to the training costs?"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 95 of IFRS 15 requires an entity to recognise an asset from the costs incurred to fulfil a contract with a customer if the costs are not within the scope of another IFRS Standard, and only if those costs meet all three criteria specified in paragraph 95. Consequently, before assessing the criteria in paragraph 95, the entity first considers whether the training costs incurred to fulfil the contract are within the scope of another IFRS Standard."}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs 2\u20137 of IAS 38 describe the scope of that Standard\u2014paragraph 5 explicitly includes expenditure on training within IAS 38\u2019s scope, stating that IAS 38 \u2018applies to, among other things, expenditure on advertising, training, start-up, research and development activities\u2019. Accordingly, the Committee concluded that, in the fact pattern described in the request, the entity applies IAS 38 in accounting for the training costs incurred to fulfil the contract with the customer."}),"\n",(0,a.jsx)(t.h2,{id:"application-of-ias-38",children:"Application of IAS 38"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 69(b) of IAS 38 includes expenditure on training activities as an example of expenditure that is incurred \u2018to provide future economic benefits to an entity, but no intangible asset or other asset is acquired or created that can be recognised\u2019. Consequently, paragraph 69 states that such expenditure on training activities is recognised as an expense when incurred. Paragraph 15 of IAS 38 explains that \u2018an entity usually has insufficient control over the expected future economic benefits arising from a team of skilled staff and from training for these items to meet the definition of an\nintangible asset\u2019."}),"\n",(0,a.jsx)(t.p,{children:"In addition, in explaining the requirements in IFRS 15 regarding costs to fulfil a contract, paragraph BC307 of IFRS 15 states that \u2018if the other Standards preclude the recognition of any asset arising from a particular cost, an asset cannot then be recognised under IFRS 15\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Accordingly, the Committee concluded that, in the fact pattern described in the request, the entity recognises the training costs to fulfil the contract with the customer as an expense when incurred. The Committee noted that the entity\u2019s ability to charge to the customer the costs of training does not affect that conclusion."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS 15 and IAS 38 provide an adequate basis for an entity to determine its accounting for training costs incurred to fulfil a contract with a customer. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function h(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(f,{...e})}):f(e)}},28453(e,t,i){i.d(t,{R:()=>s,x:()=>r});var n=i(96540);let a={},o=n.createContext(a);function s(e){let t=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);